import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
  TouchableOpacity,
  Image,
} from 'react-native';
import { TextInput, Button, Text, SegmentedButtons, IconButton } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';

export default function AddProductScreen({ navigation }) {
  const [formData, setFormData] = useState({
    name: '',
    category: 'Vegetables',
    price: '',
    stock: '',
    unit: 'kg',
    description: '',
  });
  const [loading, setLoading] = useState(false);

  const updateFormData = (key, value) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleSubmit = async () => {
    if (!formData.name || !formData.price || !formData.stock) {
      alert('Please fill in all required fields');
      return;
    }

    setLoading(true);
    try {
      // In production, this would be an API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      alert('Product added successfully!');
      navigation.goBack();
    } catch (error) {
      alert('Failed to add product');
    } finally {
      setLoading(false);
    }
  };

  return (
    <KeyboardAvoidingView
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      style={styles.container}
    >
      <View style={styles.header}>
        <IconButton
          icon="arrow-left"
          size={24}
          onPress={() => navigation.goBack()}
        />
        <Text style={styles.headerTitle}>Add New Product</Text>
        <View style={{ width: 48 }} />
      </View>

      <ScrollView style={styles.content}>
        {/* Image Upload */}
        <TouchableOpacity style={styles.imageUpload}>
          <Icon name="camera" size={40} color="#999" />
          <Text style={styles.imageUploadText}>Add Product Photo</Text>
        </TouchableOpacity>

        {/* Product Name */}
        <TextInput
          label="Product Name *"
          value={formData.name}
          onChangeText={(text) => updateFormData('name', text)}
          mode="outlined"
          style={styles.input}
        />

        {/* Category */}
        <Text style={styles.label}>Category *</Text>
        <SegmentedButtons
          value={formData.category}
          onValueChange={(value) => updateFormData('category', value)}
          buttons={[
            { value: 'Vegetables', label: 'Vegetables' },
            { value: 'Fruits', label: 'Fruits' },
            { value: 'Grains', label: 'Grains' },
            { value: 'Dairy', label: 'Dairy' },
          ]}
          style={styles.segmentedButtons}
        />

        {/* Price and Unit */}
        <View style={styles.row}>
          <TextInput
            label="Price per unit *"
            value={formData.price}
            onChangeText={(text) => updateFormData('price', text)}
            mode="outlined"
            keyboardType="numeric"
            style={[styles.input, { flex: 1, marginRight: 10 }]}
            left={<TextInput.Affix text="₹" />}
          />
          <TextInput
            label="Unit"
            value={formData.unit}
            onChangeText={(text) => updateFormData('unit', text)}
            mode="outlined"
            style={[styles.input, { width: 100 }]}
          />
        </View>

        {/* Stock */}
        <TextInput
          label="Available Stock *"
          value={formData.stock}
          onChangeText={(text) => updateFormData('stock', text)}
          mode="outlined"
          keyboardType="numeric"
          style={styles.input}
          right={<TextInput.Affix text={formData.unit} />}
        />

        {/* Description */}
        <TextInput
          label="Description"
          value={formData.description}
          onChangeText={(text) => updateFormData('description', text)}
          mode="outlined"
          multiline
          numberOfLines={4}
          style={styles.input}
        />

        {/* Organic Toggle */}
        <View style={styles.switchRow}>
          <Text style={styles.switchLabel}>Organic Product</Text>
          <Icon name="leaf" size={24} color="#2E7D32" />
        </View>

        <Button
          mode="contained"
          onPress={handleSubmit}
          loading={loading}
          disabled={loading}
          style={styles.submitButton}
          buttonColor="#2E7D32"
        >
          Add Product
        </Button>
      </ScrollView>
    </KeyboardAvoidingView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingTop: 50,
    paddingHorizontal: 10,
    backgroundColor: '#fff',
    elevation: 2,
  },
  headerTitle: {
    fontSize: 18,
    fontWeight: 'bold',
  },
  content: {
    flex: 1,
    padding: 20,
  },
  imageUpload: {
    height: 200,
    backgroundColor: '#f0f0f0',
    borderRadius: 12,
    borderWidth: 2,
    borderColor: '#ddd',
    borderStyle: 'dashed',
    justifyContent: 'center',
    alignItems: 'center',
    marginBottom: 20,
  },
  imageUploadText: {
    marginTop: 10,
    color: '#999',
    fontSize: 14,
  },
  input: {
    marginBottom: 15,
  },
  label: {
    fontSize: 14,
    color: '#666',
    marginBottom: 10,
  },
  segmentedButtons: {
    marginBottom: 15,
  },
  row: {
    flexDirection: 'row',
  },
  switchRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingVertical: 15,
    paddingHorizontal: 10,
    backgroundColor: '#f9f9f9',
    borderRadius: 8,
    marginBottom: 20,
  },
  switchLabel: {
    fontSize: 16,
    color: '#333',
  },
  submitButton: {
    marginTop: 10,
    marginBottom: 30,
    paddingVertical: 6,
  },
});
